20	function initSchema(db: Database) {
21	  db.run(`
22	    CREATE TABLE IF NOT EXISTS schema_version (version INTEGER PRIMARY KEY)
23	  `);
24	  const row = db.query("SELECT version FROM schema_version").get() as { version: number } | null;
25	  if (row && row.version >= 1) return;
26	
27	  db.run(`
28	    CREATE TABLE IF NOT EXISTS eval_runs (
29	      run_id TEXT PRIMARY KEY,
30	      timestamp TEXT NOT NULL,
31	      trials INTEGER DEFAULT 1,
32	      scenarios_run INTEGER,
33	      scenarios_total INTEGER,
34	      is_complete_baseline INTEGER DEFAULT 0,
35	      pass_count INTEGER,
36	      partial_count INTEGER,
37	      fail_count INTEGER,
38	      pass_rate REAL,
39	      meta TEXT
40	    )
41	  `);
42	
43	  db.run(`
44	    CREATE TABLE IF NOT EXISTS eval_results (
45	      id INTEGER PRIMARY KEY AUTOINCREMENT,
46	      run_id TEXT NOT NULL REFERENCES eval_runs(run_id),
47	      agent TEXT NOT NULL,
48	      scenario_id TEXT NOT NULL,
49	      trial_index INTEGER DEFAULT 0,
50	      score TEXT NOT NULL,
51	      confidence_stated REAL,
52	      justification TEXT,
53	      observations TEXT,
54	      grader_results TEXT,
55	      grader_override INTEGER DEFAULT 0,
56	      duration_ms INTEGER,
57	      tokens_used INTEGER,
58	      input_tokens INTEGER,
59	      output_tokens INTEGER,
60	      cost_usd REAL,
61	      agent_output_excerpt TEXT,
62	      failure_reason TEXT,
63	      trace TEXT,
64	      agent_output TEXT,
65	      scenario_name TEXT,
66	      scenario_type TEXT,
67	      category TEXT,
68	      UNIQUE(run_id, agent, scenario_id, trial_index)
69	    )
70	  `);
71	
72	  db.run(`
73	    CREATE TABLE IF NOT EXISTS agent_summaries (
74	      run_id TEXT NOT NULL REFERENCES eval_runs(run_id),
75	      agent TEXT NOT NULL,
76	      pass_count INTEGER,
77	      partial_count INTEGER,
78	      fail_count INTEGER,
79	      pass_rate REAL,
80	      avg_confidence_stated REAL,
81	      calibration_gap REAL,
82	      PRIMARY KEY (run_id, agent)
83	    )
84	  `);
85	
86	  db.run(`INSERT OR IGNORE INTO schema_version (version) VALUES (1)`);
87	}
