197	/**
198	 * Bulk query: returns a Map<run_id, string[]> of agents for a specific set of run IDs.
199	 * Agents are deduplicated and sorted alphabetically per run.
200	 * Uses agent_summaries with fallback to eval_results (same logic as getAgentsForAllRuns).
201	 */
202	export function getAgentsForRuns(runIds: string[]): Map<string, string[]> {
203	  if (runIds.length === 0) return new Map();
204	  const db = getDb();
205	  const map = new Map<string, string[]>();
206	  const placeholders = runIds.map(() => "?").join(",");
207	
208	  const summaryRows = db.query(
209	    `SELECT run_id, agent FROM agent_summaries WHERE run_id IN (${placeholders}) ORDER BY run_id, agent ASC`
210	  ).all(...runIds) as { run_id: string; agent: string }[];
211	  for (const row of summaryRows) {
212	    if (!map.has(row.run_id)) map.set(row.run_id, []);
213	    map.get(row.run_id)!.push(row.agent);
214	  }
215	
216	  const coveredIds = [...map.keys()];
217	  const uncoveredIds = runIds.filter(id => !coveredIds.includes(id));
218	  if (uncoveredIds.length > 0) {
219	    const fallbackPlaceholders = uncoveredIds.map(() => "?").join(",");
220	    const fallbackRows = db.query(
221	      `SELECT DISTINCT run_id, agent FROM eval_results WHERE run_id IN (${fallbackPlaceholders}) ORDER BY run_id, agent ASC`
222	    ).all(...uncoveredIds) as { run_id: string; agent: string }[];
223	    for (const row of fallbackRows) {
224	      if (!map.has(row.run_id)) map.set(row.run_id, []);
225	      map.get(row.run_id)!.push(row.agent);
226	    }
227	  }
228	
229	  return map;
230	}
