232	/**
233	 * Bulk query: returns a Map<run_id, string[]> of agents for all runs.
234	 * Agents are deduplicated and sorted alphabetically per run.
235	 * Uses agent_summaries (more reliable for completed runs) with fallback to eval_results.
236	 */
237	export function getAgentsForAllRuns(): Map<string, string[]> {
238	  const db = getDb();
239	  const map = new Map<string, string[]>();
240	
241	  // Primary: agent_summaries (populated for completed runs)
242	  const summaryRows = db.query(
243	    "SELECT run_id, agent FROM agent_summaries ORDER BY run_id, agent ASC"
244	  ).all() as { run_id: string; agent: string }[];
245	  for (const row of summaryRows) {
246	    if (!map.has(row.run_id)) map.set(row.run_id, []);
247	    map.get(row.run_id)!.push(row.agent);
248	  }
249	
250	  // Fallback: eval_results only for run_ids NOT already covered by agent_summaries
251	  // This handles in-progress or crashed runs that never wrote agent_summaries rows.
252	  const fallbackRows = db.query(
253	    "SELECT DISTINCT run_id, agent FROM eval_results WHERE run_id NOT IN (SELECT DISTINCT run_id FROM agent_summaries) ORDER BY run_id, agent ASC"
254	  ).all() as { run_id: string; agent: string }[];
255	  for (const row of fallbackRows) {
256	    if (!map.has(row.run_id)) map.set(row.run_id, []);
257	    map.get(row.run_id)!.push(row.agent);
258	  }
259	
260	  return map;
261	}
