328	export type ScenarioHistoryEntry = {
329	  run_id: string;
330	  timestamp: string;
331	  score: string;
332	};
333	
334	/**
335	 * Returns the score history for a given agent+scenario across ALL runs,
336	 * ordered by timestamp ascending. Uses worst score across trials per run.
337	 */
338	export function getScenarioHistory(agent: string, scenarioId: string): ScenarioHistoryEntry[] {
339	  const db = getDb();
340	  // Get all runs ordered by timestamp ascending
341	  const runs = db.query("SELECT run_id, timestamp FROM eval_runs ORDER BY timestamp ASC").all() as { run_id: string; timestamp: string }[];
342	  const result: ScenarioHistoryEntry[] = [];
343	  for (const run of runs) {
344	    const rows = db.query(
345	      "SELECT score FROM eval_results WHERE run_id = ? AND agent = ? AND scenario_id = ? ORDER BY score ASC"
346	    ).all(run.run_id, agent, scenarioId) as { score: string }[];
347	    if (rows.length === 0) continue;
348	    // Use worst score across trials
349	    const scoreOrdFn = (s: string) => s === "fail" ? 0 : s === "partial" ? 1 : 2;
350	    const worst = rows.reduce((w, r) => scoreOrdFn(r.score) < scoreOrdFn(w.score) ? r : w, rows[0]);
351	    result.push({ run_id: run.run_id, timestamp: run.timestamp, score: worst.score });
352	  }
353	  return result;
354	}
355	
356	/**
357	 * Returns all agent+scenario pairs that have NEVER passed across ALL runs.
358	 * Returns: array of { agent, scenario_id, history: ScenarioHistoryEntry[] }
359	 */
360	export function getPersistentNonPassScenarios(): Array<{
361	  agent: string;
362	  scenario_id: string;
363	  history: ScenarioHistoryEntry[];
364	}> {
365	  const db = getDb();
366	  // Find all agent+scenario combos that appear in at least 2 runs and never passed
367	  const rows = db.query(`
368	    SELECT agent, scenario_id
369	    FROM eval_results
370	    GROUP BY agent, scenario_id
371	    HAVING COUNT(DISTINCT run_id) >= 2
372	      AND SUM(CASE WHEN score = 'pass' THEN 1 ELSE 0 END) = 0
373	    ORDER BY agent, scenario_id
374	  `).all() as { agent: string; scenario_id: string }[];
375	
376	  return rows.map(row => ({
377	    agent: row.agent,
378	    scenario_id: row.scenario_id,
379	    history: getScenarioHistory(row.agent, row.scenario_id),
380	  }));
381	}
