39	    args.push("--agent", opts.agents.join(","));
40	  }
41	  // Pass selected scenarios as comma-separated "agent/scenario-id" values to --scenario (BR-5)
42	  // Keep full agent/scenario-id format to avoid cross-agent basename collisions
43	  const selectedScenarios = opts.scenarios
44	    .filter(s => s.trim().length > 0);
