1	export type WeightClass = "standard" | "heavy" | "freight";
2	
3	/**
4	 * Classifies a parcel weight into a bracket.
5	 *
6	 * Brackets:
7	 *   standard : 0 < weight < 10
8	 *   heavy    : 10 <= weight < 50
9	 *   freight  : 50 <= weight <= 1000
10	 *
11	 * @throws {Error} if weight <= 0 or weight > 1000
12	 */
13	export function classifyWeight(weight: number): WeightClass {
14	  if (weight <= 0 || weight > 1000) {
15	    throw new Error(
16	      `Invalid weight: ${weight}. Weight must be greater than 0 and at most 1000 kg.`
17	    );
18	  }
19	
20	  if (weight < 10) {
21	    return "standard";
22	  }
23	
24	  if (weight < 50) {
25	    return "heavy";
26	  }
27	
28	  return "freight";
29	}
